def count_politician_names(articles, politician_names):
    politician_counts = {}
    for article in articles:
        # process the article to extract names
        for name in politician_names:
            # remove punctuation and convert to lowercase
            name_lower = name.lower()
            article_lower = article.lower()
            # remove punctuation from article
            cleaned_article = ''.join(c for c in article_lower if c.isalnum())
            if name_lower in cleaned_article:
                politician_counts[name_lower] = politician_counts.get(name_lower, 0) + 1
    return politician_counts

